// Parse the ExecutionPlan from worker_soar and enrich with workspace IOCs.
// Fields available from worker_soar body_template (SoarExecutionSchema-derived):
//   incident_id, target, targets[], action, action_type, source_type, reason
const fs = require('fs');
const body = $input.first().json.body || $input.first().json;

const incidentId = body.incident_id || 'UNKNOWN';
const target     = body.target || body.target_sensor || '';
const targets    = (Array.isArray(body.targets) ? body.targets : [target]).filter(Boolean);
const actionType = body.action_type || body.action || 'isolate_host';
const sourceType = body.source_type || '';
const reason     = body.reason || '';

// Derive platform and cloud provider from source_type
const AWS_SOURCES   = ['aws_cloudtrail','aws_vpc_flow','aws_guardduty'];
const AZURE_SOURCES = ['azure_entraid','azure_activity','azure_nsg_flow'];
const GCP_SOURCES   = ['gcp_audit','gcp_scc','gcp_vpc_flow'];

const isWindows = sourceType.toLowerCase().startsWith('windows') ||
                  (body.platform || '').toLowerCase() === 'windows';
const isCloud   = (body.platform || '').toLowerCase() === 'cloud' ||
                  AWS_SOURCES.includes(sourceType) ||
                  AZURE_SOURCES.includes(sourceType) ||
                  GCP_SOURCES.includes(sourceType);

let cloudProvider = body.cloud_provider || '';
if (!cloudProvider) {
  if (AWS_SOURCES.includes(sourceType))        cloudProvider = 'aws';
  else if (AZURE_SOURCES.includes(sourceType)) cloudProvider = 'azure';
  else if (GCP_SOURCES.includes(sourceType))   cloudProvider = 'gcp';
}

const platform = isCloud ? 'cloud' : (isWindows ? 'windows' : 'linux');

// Read incident context injected by trigger-incident.sh via shared volume.
// The n8n Dockerfile exposes /incident-context → ../webui/data.
let context = [];
try {
  const raw = fs.readFileSync('/incident-context/workspace_context.json', 'utf8');
  const parsed = JSON.parse(raw);
  if (Array.isArray(parsed.context)) context = parsed.context;
} catch (e) {
  // Context unavailable -- proceed with payload-derived IOCs only
}

// Extract IOCs from every context record (swarm-enriched telemetry)
const c2IPs        = new Set();
const maliciousPids = new Set();
const maliciousProcs = new Set();
const maliciousHashes = new Set();
const maliciousPaths = new Set();
const c2Domains    = new Set();

const rfc1918 = /^(10\.|192\.168\.|172\.(1[6-9]|2[0-9]|3[0-1])\.|127\.)/;

for (const r of context) {
  if (r.dst_ip && !rfc1918.test(r.dst_ip)) c2IPs.add(r.dst_ip);
  if (r.pid)            maliciousPids.add(String(r.pid));
  if (r.comm)           maliciousProcs.add(r.comm);
  if (r.process_name)   maliciousProcs.add(r.process_name);
  if (r.process_hash && r.process_hash.length === 64) maliciousHashes.add(r.process_hash);
  if (r.target_file)    maliciousPaths.add(r.target_file);
  if (r.path)           maliciousPaths.add(r.path);
  if (r.dns_query)      c2Domains.add(r.dns_query);
}

// Merge any additional IOCs worker_soar packed into the payload body
if (body.c2_ips)    body.c2_ips.split(',').forEach(ip => { const t = ip.trim(); if (t) c2IPs.add(t); });
if (body.c2_domains) body.c2_domains.split(',').forEach(d => { const t = d.trim(); if (t) c2Domains.add(t); });
if (body.malicious_pids) body.malicious_pids.split(',').forEach(p => { const t = p.trim(); if (t) maliciousPids.add(t); });

return [{
  json: {
    incident_id:      incidentId,
    action_type:      actionType,
    platform,
    cloud_provider:   cloudProvider,
    source_type:      sourceType,
    reason,
    targets,
    total_targets:    targets.length,
    c2_ips:           [...c2IPs].filter(Boolean),
    c2_domains:       [...c2Domains].filter(Boolean),
    malicious_pids:   [...maliciousPids].filter(Boolean),
    malicious_procs:  [...maliciousProcs].filter(Boolean),
    malicious_hashes: [...maliciousHashes].filter(Boolean),
    malicious_paths:  [...maliciousPaths].filter(Boolean)
  }
}];

// Build the SSH command that invokes run_containment.sh for this target.
// Explicitly invokes bash so the script runs regardless of volume execute bit.
const item          = $input.first().json;
const target        = item.current_target  || '';
const incidentId    = item.incident_id     || 'UNKNOWN';
const platform      = item.platform        || 'linux';
const c2Ips      = (item.c2_ips           || []).join(',');
const mgmtIps    = process.env.NEXUS_MGMT_IPS || '';
const pids       = (item.malicious_pids   || []).join(',');
const procs      = (item.malicious_procs  || []).join(',');
const hashes     = (item.malicious_hashes || []).join(',');
const paths      = (item.malicious_paths  || []).join(',');
const c2Domains  = (item.c2_domains       || []).join(',');

// Single-quote-escape each argument so the shell receives literal strings.
// Values from swarm analysis are IPs/hashes/paths -- unlikely to contain quotes,
// but we sanitize defensively.
const q = v => `'${v.replace(/'/g, "'\\''")}' `;

const args = [
  q(target), q(incidentId), q(platform), q(c2Ips), q(mgmtIps),
  q(pids),   q(procs),      q(hashes),   q(paths), q(c2Domains)
].join(' ');

// For cloud platform, prepend provider env so run_cloud_playbook() picks it up.
// Container already has NEXUS_AWS_REGION / NEXUS_AZURE_* / NEXUS_GCP_* from docker-compose.
const cloudProvider = item.cloud_provider || '';
const envPrefix = platform === 'cloud' && cloudProvider
  ? `NEXUS_CLOUD_PROVIDER=${cloudProvider} `
  : '';

return [{
  json: {
    ...item,
    current_target: target,
    ssh_command: `${envPrefix}bash /playbooks/run_containment.sh ${args}`
  }
}];

// One item emitted per successful target -- Aggregate counts these items.
const item      = $input.first().json;
const target    = item.current_target || 'unknown';
const stdout    = item.stdout || '';
const incidentId = $('Parse Payload & Enrich IOCs').first().json.incident_id;

let phaseDetail = {};
try {
  const lastLine = stdout.trim().split('\n').pop();
  phaseDetail = JSON.parse(lastLine);
} catch (e) {
  phaseDetail = { status: 'success', note: 'no structured output' };
}

return [{ json: { incident_id: incidentId, target_result: 'success', target, detail: phaseDetail } }];

// One item emitted per failed target -- Aggregate counts these items.
const item      = $input.first().json;
const target    = item.current_target || 'unknown';
const errMsg    = item.stderr || item.error?.message || 'runner error';
const incidentId = $('Parse Payload & Enrich IOCs').first().json.incident_id;

return [{ json: {
  incident_id:   incidentId,
  target_result: 'failed',
  target,
  error: { target, message: errMsg.substring(0, 300), timestamp: new Date().toISOString() }
}}];

// Count items from both Track nodes to compute the final status.
// Each item represents one target's outcome (success or failure).
const items = $input.all();

const succeeded = items.filter(i => i.json.target_result === 'success');
const failed    = items.filter(i => i.json.target_result === 'failed');
const errors    = failed.map(i => i.json.error).filter(Boolean);
const incidentId = items.find(i => i.json.incident_id)?.json.incident_id || 'UNKNOWN';

const status = failed.length === 0 ? 'CONTAINED' :
               succeeded.length === 0 ? 'FAILED'    : 'PARTIAL_FAILURE';

return [{
  json: {
    incident_id:   incidentId,
    status,
    total_targets: items.length,
    completed:     succeeded.length,
    failed:        failed.length,
    errors,
    source:        'fallback_playbooks',
    timestamp:     new Date().toISOString()
  }
}];
